const taches = $input.all().map(i => i.json);
const aujourdhui = new Date();
const enRetard = taches.filter(t => t.deadline && new Date(t.deadline) < aujourdhui);
const bloquees = taches.filter(t => t.statut === 'bloquee');
const urgentes = taches.filter(t => t.deadline && new Date(t.deadline) >= aujourdhui);
const lignes = taches.map(t => `- [${t.projet} / ${t.client}] ${t.titre} — ${t.assigne_email || 'non assigné'} — échéance ${t.deadline || 'n/a'} — ${t.statut}${t.priorite ? ' (' + t.priorite + ')' : ''}`).join('\n');
return [{ json: {
  nb_total: taches.length,
  nb_retard: enRetard.length,
  nb_bloquees: bloquees.length,
  nb_urgentes: urgentes.length,
  detail: lignes,
  taches
} }];

